use std::collections::BTreeMap;
use std::error::Error;
use std::fs;
use std::path::Path;

use time::OffsetDateTime;

use super::rig_client;

// Generated by build.rs from src/rig/r-versions.json:
// - EMBEDDED_MINOR_RELEASES_FETCHED_AT: &str
// - embedded_minor_releases() -> Vec<MinorRelease>
include!(concat!(env!("OUT_DIR"), "/r_version_releases.rs"));

#[derive(serde::Deserialize, serde::Serialize)]
struct MinorRelease {
    major: u64,
    minor: u64,
    date: String,
}

#[derive(serde::Deserialize)]
struct RigAvailableRelease {
    #[serde(default)]
    name: String,
    version: String,
    date: Option<String>,
}

#[derive(serde::Deserialize, serde::Serialize)]
struct CachedMinorReleases {
    fetched_at: String,
    releases: Vec<MinorRelease>,
}

pub(crate) fn latest_minor_version_on(exclude_newer: &str) -> Result<String, Box<dyn Error>> {
    let releases = minor_releases_for(exclude_newer)?;
    let release = latest_minor_release_on(&releases, exclude_newer).ok_or_else(|| {
        format!("could not resolve latest R minor version available before or on {exclude_newer}")
    })?;

    Ok(format!("{}.{}", release.major, release.minor))
}

fn minor_releases_for(exclude_newer: &str) -> Result<Vec<MinorRelease>, Box<dyn Error>> {
    if exclude_newer <= EMBEDDED_MINOR_RELEASES_FETCHED_AT {
        return Ok(embedded_minor_releases());
    }

    Ok(cached_minor_releases(exclude_newer)?.releases)
}

fn latest_minor_release_on<'a>(
    releases: &'a [MinorRelease],
    exclude_newer: &str,
) -> Option<&'a MinorRelease> {
    releases
        .iter()
        .filter(|release| release.date.as_str() <= exclude_newer)
        .max_by_key(|release| (release.major, release.minor))
}

fn cached_minor_releases(exclude_newer: &str) -> Result<CachedMinorReleases, Box<dyn Error>> {
    let path = crate::runtime::ir_cache_dir()?
        .join("rig")
        .join("minor-releases.json");
    if path.exists() {
        let json = fs::read_to_string(&path)
            .map_err(|e| format!("failed to read `{}`: {e}", path.display()))?;
        let cache = parse_cached_minor_releases_json(&json, &path)?;
        if cache.fetched_at.as_str() >= exclude_newer {
            return Ok(cache);
        }
    }

    let cache = CachedMinorReleases {
        fetched_at: utc_today_string(),
        releases: fetch_minor_releases()?,
    };
    let json = serde_json::to_string_pretty(&cache)
        .map_err(|e| format!("failed to serialize cached R minor release metadata: {e}"))?;
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)
            .map_err(|e| format!("failed to create `{}`: {e}", parent.display()))?;
    }
    fs::write(&path, json).map_err(|e| format!("failed to write `{}`: {e}", path.display()))?;
    Ok(cache)
}

fn parse_cached_minor_releases_json(
    json: &str,
    path: &Path,
) -> Result<CachedMinorReleases, Box<dyn Error>> {
    let cache: CachedMinorReleases = serde_json::from_str(json)
        .map_err(|e| format!("failed to parse `{}` JSON: {e}", path.display()))?;
    if !is_iso_date(&cache.fetched_at) {
        return Err(format!(
            "`{}` has an invalid `fetched_at` date; expected YYYY-MM-DD",
            path.display()
        )
        .into());
    }
    for release in &cache.releases {
        if !is_iso_date(&release.date) {
            return Err(format!(
                "`{}` has an invalid R {}.{} release date; expected YYYY-MM-DD",
                path.display(),
                release.major,
                release.minor
            )
            .into());
        }
    }
    Ok(cache)
}

fn fetch_minor_releases() -> Result<Vec<MinorRelease>, Box<dyn Error>> {
    let json = String::from_utf8(rig_client::output(&["available", "--all", "--json"])?)
        .map_err(|e| format!("`rig available --all --json` returned non-UTF-8 output: {e}"))?;
    let available: Vec<RigAvailableRelease> = serde_json::from_str(&json)
        .map_err(|e| format!("failed to parse `rig available --all --json` JSON: {e}"))?;

    let mut by_minor = BTreeMap::new();
    for release in available {
        if matches!(release.name.as_str(), "devel" | "next") {
            continue;
        }
        let Some((major, minor, _patch)) = version_parts(&release.version) else {
            continue;
        };
        if major < 3 {
            continue;
        }
        let Some(date) = release.date.as_deref().and_then(iso_date_prefix) else {
            continue;
        };
        by_minor
            .entry((major, minor))
            .and_modify(|previous: &mut String| {
                if date < previous.as_str() {
                    *previous = date.to_string();
                }
            })
            .or_insert_with(|| date.to_string());
    }

    Ok(by_minor
        .into_iter()
        .map(|((major, minor), date)| MinorRelease { major, minor, date })
        .collect())
}

fn version_parts(value: &str) -> Option<(u64, u64, u64)> {
    let mut parts = value.split('.');
    let major = parts.next()?.parse().ok()?;
    let minor = parts.next()?.parse().ok()?;
    let patch = parts.next()?.parse().ok()?;
    if parts.next().is_some() {
        return None;
    }
    Some((major, minor, patch))
}

fn iso_date_prefix(value: &str) -> Option<&str> {
    let date = value.get(..10)?;
    if is_iso_date(date) {
        Some(date)
    } else {
        None
    }
}

fn is_iso_date(value: &str) -> bool {
    let bytes = value.as_bytes();
    bytes.len() == 10
        && bytes[0].is_ascii_digit()
        && bytes[1].is_ascii_digit()
        && bytes[2].is_ascii_digit()
        && bytes[3].is_ascii_digit()
        && bytes[4] == b'-'
        && bytes[5].is_ascii_digit()
        && bytes[6].is_ascii_digit()
        && bytes[7] == b'-'
        && bytes[8].is_ascii_digit()
        && bytes[9].is_ascii_digit()
}

fn utc_today_string() -> String {
    let today = OffsetDateTime::now_utc().date();
    format!(
        "{:04}-{:02}-{:02}",
        today.year(),
        u8::from(today.month()),
        today.day()
    )
}
